        let parent_weak = p.borrow().parent_node.clone();

        if let Some(ref parent_rc) = parent_weak.and_then(|w| w.upgrade()) {
            let is_left = Rc::ptr_eq(parent_rc.borrow().left_child_node.as_ref().unwrap(), p);
            if is_left {
                parent_rc.borrow_mut().left_child_node = Some(Rc::clone(&l));
            } else {
                parent_rc.borrow_mut().right_child_node = Some(Rc::clone(&l));
            }
        } else {
            // Note: caller must update root_node if needed
        }

        l.borrow_mut().parent_node = parent_weak.clone();

        let l_right = l.borrow().right_child_node.clone();
        let l_right_count = l.borrow().right_child_count;
        p.borrow_mut().left_child_node = l_right;
        p.borrow_mut().left_child_count = l_right_count;
        if let Some(ref rc) = p.borrow().left_child_node {
            rc.borrow_mut().parent_node = Some(Rc::downgrade(p));
        }

        p.borrow_mut().depth = imax(left_depth(&p.borrow()), right_depth(&p.borrow()));
        p.borrow_mut().parent_node = Some(Rc::downgrade(&l));

        l.borrow_mut().right_child_node = Some(Rc::clone(p));
        l.borrow_mut().right_child_count = p.borrow().left_child_count + p.borrow().right_child_count + 1;
        l.borrow_mut().depth = imax(left_depth(&l.borrow()), right_depth(&l.borrow()));

