}

/// Return the next node in an in-order traversal.
pub fn bostree_next_node(node: &Rc<RefCell<BOSNode>>) -> Option<Rc<RefCell<BOSNode>>> {
    if let Some(ref right) = node.borrow().right_child_node {
        let mut current = Rc::clone(right);
        while current.borrow().left_child_node.is_some() {
            let next = Rc::clone(current.borrow().left_child_node.as_ref().unwrap());
            current = next;
        }
        Some(current)
    } else {
        let mut current = Rc::clone(node);
        loop {
            let parent_weak = current.borrow().parent_node.clone();
            match parent_weak.and_then(|p| p.upgrade()) {
                Some(p) => {
                    let is_right = p.borrow().right_child_node.as_ref().map_or(false, |r| Rc::ptr_eq(r, &current));
                    if is_right {
                        current = p;
                    } else {
                        return Some(p);
                    }
                }
                None => return None,
            }
        }
    }
}

/// Return the previous node in an in-order traversal.
pub fn bostree_previous_node(node: &Rc<RefCell<BOSNode>>) -> Option<Rc<RefCell<BOSNode>>> {
    if let Some(ref left) = node.borrow().left_child_node {
        let mut current = Rc::clone(left);
        while current.borrow().right_child_node.is_some() {
            let next = Rc::clone(current.borrow().right_child_node.as_ref().unwrap());
            current = next;
