            l_right_count = l_borrow.right_child_count;
        }
        p.borrow_mut().left_child_node = l_right;
        p.borrow_mut().left_child_count = l_right_count;
        if let Some(ref rc) = p.borrow().left_child_node {
            rc.borrow_mut().parent_node = Some(Rc::downgrade(p));
        }

        {
            let (pld, prd);
            let pb = p.borrow();
            pld = match pb.left_child_node.as_ref() {
                Some(child) => child.borrow().depth + 1,
                None => 0,
            };
            prd = match pb.right_child_node.as_ref() {
                Some(child) => child.borrow().depth + 1,
                None => 0,
            };
            p.borrow_mut().depth = imax(pld, prd);
        }
        p.borrow_mut().parent_node = Some(Rc::downgrade(&l));

        l.borrow_mut().right_child_node = Some(Rc::clone(p));
        {
            let pb = p.borrow();
            l.borrow_mut().right_child_count = pb.left_child_count + pb.right_child_count + 1;
        }
        {
            let (lld, lrd);
            let lb = l.borrow();
            lld = match lb.left_child_node.as_ref() {
                Some(child) => child.borrow().depth + 1,
                None => 0,
            };
            lrd = match lb.right_child_node.as_ref() {
                Some(child) => child.borrow().depth + 1,
                None => 0,
            };
            l.borrow_mut().depth = imax(lld, lrd);
        }

        l
    }

    /// Decrease the weak reference count for a node.
    pub fn bostree_node_weak_unref(
        &mut self,
        node: &Rc<RefCell<BOSNode>>,
    ) -> Option<Rc<RefCell<BOSNode>>> {
        node.borrow_mut().weak_ref_count -= 1;
        let count = node.borrow().weak_ref_count;
        if count == 0 {
            if let Some(free_fn) = self.free_function {
                free_fn(node);
            }
            None
        } else if node.borrow().weak_ref_node_valid != 0 {
            Some(Rc::clone(node))
        } else {
            None
        }
    }

    /// Lookup a node in the tree by its key.
    pub fn bostree_lookup(&self, key: &str) -> Option<Rc<RefCell<BOSNode>>> {
        let mut node = self.root_node.as_ref().map(Rc::clone);
        while let Some(current) = node {
            let cmp = (self.cmp_function)(key, &current.borrow().key);
            if cmp == 0 {
                return Some(current);
            } else if cmp < 0 {
                node = current.borrow().left_child_node.as_ref().map(Rc::clone);
            } else {
                node = current.borrow().right_child_node.as_ref().map(Rc::clone);
            }
        }
        None
    }

    /// Return the node at the given in-order index (starting at 0).
    pub fn bostree_select(&self, index: u32) -> Option<Rc<RefCell<BOSNode>>> {
        let mut node = self.root_node.as_ref().map(Rc::clone);
        let mut idx = index;
        while let Some(current) = node {
            let left_count = current.borrow().left_child_count;
            if left_count <= idx {
                idx -= left_count;
                if idx == 0 {
                    return Some(current);
                }
                idx -= 1;
                node = current.borrow().right_child_node.as_ref().map(Rc::clone);
            } else {
                node = current.borrow().left_child_node.as_ref().map(Rc::clone);
            }
        }
        None
    }

    /// Print the tree (only available in debug builds).
    #[cfg(debug_assertions)]
    pub fn bostree_print(&self) {
        if let Some(ref root) = self.root_node {
            println!("digraph {{\n  ordering = out;");
            Self::print_helper(root);
            println!("}}");
        }
    }

    #[cfg(debug_assertions)]
    fn print_helper(node: &Rc<RefCell<BOSNode>>) {
        let n = node.borrow();
        println!("  {} [label=\"\\N ({},{},{})\"];", n.key, n.left_child_count, n.right_child_count, n.depth);
        if let Some(ref parent_weak) = n.parent_node {
            if let Some(parent) = parent_weak.upgrade() {
                println!("  {} -> {} [color=green];", n.key, parent.borrow().key);
            }
        }
        if let Some(ref left) = n.left_child_node {
            println!("  {} -> {}", n.key, left.borrow().key);
            Self::print_helper(left);
        }
        if let Some(ref right) = n.right_child_node {
            println!("  {} -> {}", n.key, right.borrow().key);
            Self::print_helper(right);
        }
    }
}

/// Increase the weak reference count for a node and return the node.
pub fn bostree_node_weak_ref(node: &Rc<RefCell<BOSNode>>) -> Rc<RefCell<BOSNode>> {
    node.borrow_mut().weak_ref_count += 1;
    Rc::clone(node)
}

/// Return the next node in an in-order traversal.
pub fn bostree_next_node(node: &Rc<RefCell<BOSNode>>) -> Option<Rc<RefCell<BOSNode>>> {
    let right_child = node.borrow().right_child_node.clone();
    if let Some(ref right) = right_child {
        let mut current = Rc::clone(right);
        loop {
            let left_child = current.borrow().left_child_node.clone();
            match left_child {
                Some(left) => current = left,
                None => return Some(current),
            }
        }
    } else {
        let mut current = Rc::clone(node);
        loop {
            let parent_weak = current.borrow().parent_node.clone();
            match parent_weak.and_then(|p| p.upgrade()) {
                Some(p) => {
                    let is_right = p.borrow().right_child_node.as_ref().map_or(false, |r| Rc::ptr_eq(r, &current));
                    if is_right {
                        current = p;
                    } else {
                        return Some(p);
                    }
                }
                None => return None,
            }
        }
    }
}

/// Return the previous node in an in-order traversal.
pub fn bostree_previous_node(node: &Rc<RefCell<BOSNode>>) -> Option<Rc<RefCell<BOSNode>>> {
    let left_child = node.borrow().left_child_node.clone();
    if let Some(ref left) = left_child {
        let mut current = Rc::clone(left);
        loop {
            let right_child = current.borrow().right_child_node.clone();
            match right_child {
                Some(right) => current = right,
                None => return Some(current),
            }
        }
    } else {
        let mut current = Rc::clone(node);
        loop {
            let parent_weak = current.borrow().parent_node.clone();
            match parent_weak.and_then(|p| p.upgrade()) {
                Some(p) => {
                    let is_left = p.borrow().left_child_node.as_ref().map_or(false, |l| Rc::ptr_eq(l, &current));
                    if is_left {
                        current = p;
                    } else {
                        return Some(p);
                    }
                }
                None => return None,
            }
        }
    }
}

/// Return the rank (in-order index) of the given node.
pub fn bostree_rank(node: &Rc<RefCell<BOSNode>>) -> u32 {
    let mut counter = node.borrow().left_child_count;
    let mut current = Rc::clone(node);
    loop {
        let parent_weak = current.borrow().parent_node.clone();
        match parent_weak.and_then(|p| p.upgrade()) {
            Some(p) => {
                let is_right = p.borrow().right_child_node.as_ref().map_or(false, |r| Rc::ptr_eq(r, &current));
                if is_right {
                    counter += 1 + p.borrow().left_child_count;
                }
                current = p;
            }
            None => return counter,
        }
    }
}
