            // Find replacement
            let replacement = if let Some(ref left) = node.borrow().left_child_node {
                Some(Rc::clone(left))
            } else if let Some(ref right) = node.borrow().right_child_node {
                Some(Rc::clone(right))
            } else {
                None
            };

            let node_parent_weak = node.borrow().parent_node.clone();
            let parent = node_parent_weak.as_ref().and_then(|p| p.upgrade());

            // Detach node
            if let Some(ref p) = parent {
                let is_left = Rc::ptr_eq(p.borrow().left_child_node.as_ref().unwrap(), node);
                if is_left {
                    p.borrow_mut().left_child_node = None;
                } else {
                    p.borrow_mut().right_child_node = None;
                }
            }
            node.borrow_mut().parent_node = None;

            // Attach replacement
            if let Some(ref repl) = replacement {
                repl.borrow_mut().parent_node = node_parent_weak;
            }

            if let Some(ref p) = parent {
                let is_left = Rc::ptr_eq(p.borrow().left_child_node.as_ref().unwrap(), node);
                if is_left {
                    p.borrow_mut().left_child_node = replacement;
                } else {
                    p.borrow_mut().right_child_node = replacement;
                }
            } else {
                self.root_node = replacement;
            }

            // Walk up from parent, decrementing counts and fixing balance
            let mut bubble = parent;
            while let Some(current) = bubble {
                let parent_weak = current.borrow().parent_node.clone();
                let parent = parent_weak.as_ref().and_then(|pp| pp.upgrade());
                if let Some(ref pp) = parent {
                    let is_left = Rc::ptr_eq(pp.borrow().left_child_node.as_ref().unwrap(), &current);
                    if is_left {
                        pp.borrow_mut().left_child_count -= 1;
                    } else {
                        pp.borrow_mut().right_child_count -= 1;
                    }
                }
                self.fix_balance_and_counts(&current);
                bubble = parent;
            }

            self.update_root();
        }

        // Mark node as invalid and decrement weak ref count
        node.borrow_mut().weak_ref_node_valid = 0;
        node.borrow_mut().weak_ref_count -= 1;
    }

    fn update_root(&mut self) {
        if let Some(ref root) = self.root_node {
            let mut current = Rc::clone(root);
            loop {
                let parent_weak = current.borrow().parent_node.clone();
                match parent_weak.and_then(|p| p.upgrade()) {
                    Some(p) => current = p,
                    None => break,
                }
            }
            self.root_node = Some(current);
        }
    }

    fn fix_balance_and_counts(&self, node: &Rc<RefCell<BOSNode>>) -> Rc<RefCell<BOSNode>> {
        // Compute depths from children
        let left_child = node.borrow().left_child_node.clone();
        let right_child = node.borrow().right_child_node.clone();
        let ld = child_depth(&left_child);
        let rd = child_depth(&right_child);

        node.borrow_mut().depth = imax(ld, rd);

        let balance = rd as i32 - ld as i32;

        if balance > 1 {
            let right = right_child.as_ref().unwrap();
            let rc_left = right.borrow().left_child_node.clone();
            let rc_right = right.borrow().right_child_node.clone();
            let rld = child_depth(&rc_left);
            let rrd = child_depth(&rc_right);
            let right_balance = rrd as i32 - rld as i32;
            if right_balance < 0 {
                self.bostree_rotate_right(right);
            }
            self.bostree_rotate_left(node)
        } else if balance < -1 {
            let left = left_child.as_ref().unwrap();
            let lc_left = left.borrow().left_child_node.clone();
            let lc_right = left.borrow().right_child_node.clone();
            let lld = child_depth(&lc_left);
            let lrd = child_depth(&lc_right);
            let left_balance = lrd as i32 - lld as i32;
            if left_balance > 0 {
                self.bostree_rotate_left(left);
            }
            self.bostree_rotate_right(node)
        } else {
            Rc::clone(node)
        }
    }

    fn bostree_rotate_left(&self, p: &Rc<RefCell<BOSNode>>) -> Rc<RefCell<BOSNode>> {
        let r;
        let parent_weak;
        {
            let pb = p.borrow();
            r = Rc::clone(pb.right_child_node.as_ref().unwrap());
            parent_weak = pb.parent_node.clone();
        }

        // Update parent's child pointer
        if let Some(parent_rc) = parent_weak.as_ref().and_then(|w| w.upgrade()) {
            let is_left;
            {
                let prb = parent_rc.borrow();
                is_left = Rc::ptr_eq(prb.left_child_node.as_ref().unwrap(), p);
            }
            if is_left {
                parent_rc.borrow_mut().left_child_node = Some(Rc::clone(&r));
            } else {
                parent_rc.borrow_mut().right_child_node = Some(Rc::clone(&r));
            }
        }

        r.borrow_mut().parent_node = parent_weak;

        // Move R's left child to P's right
        let r_left;
        let r_left_count;
        {
            let r_borrow = r.borrow();
            r_left = r_borrow.left_child_node.clone();
            r_left_count = r_borrow.left_child_count;
        }
        p.borrow_mut().right_child_node = r_left;
        p.borrow_mut().right_child_count = r_left_count;

        {
            let right_child = p.borrow().right_child_node.clone();
            if let Some(ref rc) = right_child {
                rc.borrow_mut().parent_node = Some(Rc::downgrade(p));
            }
        }

        // Update P's depth
        {
            let left_child = p.borrow().left_child_node.clone();
            let right_child = p.borrow().right_child_node.clone();
            let pld = child_depth(&left_child);
            let prd = child_depth(&right_child);
            p.borrow_mut().depth = imax(pld, prd);
        }
        p.borrow_mut().parent_node = Some(Rc::downgrade(&r));

        // Set R's left child to P
        r.borrow_mut().left_child_node = Some(Rc::clone(p));
        {
            let left_count = p.borrow().left_child_count;
            let right_count = p.borrow().right_child_count;
            r.borrow_mut().left_child_count = left_count + right_count + 1;
        }
        {
            let left_child = r.borrow().left_child_node.clone();
            let right_child = r.borrow().right_child_node.clone();
            let rld = child_depth(&left_child);
            let rrd = child_depth(&right_child);
            r.borrow_mut().depth = imax(rld, rrd);
        }

        r
    }

    fn bostree_rotate_right(&self, p: &Rc<RefCell<BOSNode>>) -> Rc<RefCell<BOSNode>> {
        let l;
        let parent_weak;
        {
            let pb = p.borrow();
            l = Rc::clone(pb.left_child_node.as_ref().unwrap());
            parent_weak = pb.parent_node.clone();
        }

        if let Some(parent_rc) = parent_weak.as_ref().and_then(|w| w.upgrade()) {
            let is_left;
            {
                let prb = parent_rc.borrow();
                is_left = Rc::ptr_eq(prb.left_child_node.as_ref().unwrap(), p);
            }
            if is_left {
                parent_rc.borrow_mut().left_child_node = Some(Rc::clone(&l));
            } else {
                parent_rc.borrow_mut().right_child_node = Some(Rc::clone(&l));
            }
        }

        l.borrow_mut().parent_node = parent_weak;

        let l_right;
        let l_right_count;
        {
            let l_borrow = l.borrow();
            l_right = l_borrow.right_child_node.clone();
            l_right_count = l_borrow.right_child_count;
        }
        p.borrow_mut().left_child_node = l_right;
        p.borrow_mut().left_child_count = l_right_count;

        {
            let left_child = p.borrow().left_child_node.clone();
            if let Some(ref rc) = left_child {
                rc.borrow_mut().parent_node = Some(Rc::downgrade(p));
            }
        }

        {
            let left_child = p.borrow().left_child_node.clone();
            let right_child = p.borrow().right_child_node.clone();
            let pld = child_depth(&left_child);
            let prd = child_depth(&right_child);
            p.borrow_mut().depth = imax(pld, prd);
        }
        p.borrow_mut().parent_node = Some(Rc::downgrade(&l));

        l.borrow_mut().right_child_node = Some(Rc::clone(p));
        {
            let left_count = p.borrow().left_child_count;
            let right_count = p.borrow().right_child_count;
            l.borrow_mut().right_child_count = left_count + right_count + 1;
        }
        {
            let left_child = l.borrow().left_child_node.clone();
            let right_child = l.borrow().right_child_node.clone();
            let lld = child_depth(&left_child);
            let lrd = child_depth(&right_child);
            l.borrow_mut().depth = imax(lld, lrd);
        }

        l
    }

    pub fn bostree_node_weak_unref(
        &mut self,
        node: &Rc<RefCell<BOSNode>>,
    ) -> Option<Rc<RefCell<BOSNode>>> {
        node.borrow_mut().weak_ref_count -= 1;
        let count = node.borrow().weak_ref_count;
        if count == 0 {
            if let Some(free_fn) = self.free_function {
                free_fn(node);
            }
            None
        } else if node.borrow().weak_ref_node_valid != 0 {
            Some(Rc::clone(node))
        } else {
            None
        }
    }

    pub fn bostree_lookup(&self, key: &str) -> Option<Rc<RefCell<BOSNode>>> {
        let mut result = None;
        let mut current_node = self.root_node.as_ref().map(Rc::clone);
        while let Some(current) = current_node {
            let (cmp_result, next) = {
                let cb = current.borrow();
                let cmp_result = (self.cmp_function)(key, &cb.key);
                let next = if cmp_result == 0 {
                    None
                } else if cmp_result < 0 {
                    cb.left_child_node.clone()
                } else {
                    cb.right_child_node.clone()
                };
                (cmp_result, next)
            };
            if cmp_result == 0 {
                result = Some(current);
                break;
            }
            current_node = next;
        }
        result
    }

    pub fn bostree_select(&self, index: u32) -> Option<Rc<RefCell<BOSNode>>> {
        let mut result = None;
        let mut current_node = self.root_node.as_ref().map(Rc::clone);
        let mut idx = index;
        while let Some(current) = current_node {
            let (found, left_count, next) = {
                let cb = current.borrow();
                let left_count = cb.left_child_count;
                if left_count <= idx {
                    let remaining = idx - left_count;
                    if remaining == 0 {
                        (true, 0, None) // Found
                    } else {
                        idx = remaining - 1;
                        (false, 0, cb.right_child_node.clone())
                    }
                } else {
                    (false, 0, cb.left_child_node.clone())
                }
            };
            if found {
                result = Some(current);
                break;
            }
            current_node = next;
        }
        result
    }

    #[cfg(debug_assertions)]
    pub fn bostree_print(&self) {
        if let Some(ref root) = self.root_node {
            println!("digraph {{\n  ordering = out;");
            Self::print_helper(root);
            println!("}}");
        }
    }

    #[cfg(debug_assertions)]
    fn print_helper(node: &Rc<RefCell<BOSNode>>) {
        let (key, lcc, rcc, depth);
        let parent_key;
        let left_child;
        let right_child;
        {
            let n = node.borrow();
            key = n.key.clone();
            lcc = n.left_child_count;
            rcc = n.right_child_count;
            depth = n.depth;
            parent_key = n.parent_node.as_ref().and_then(|p| p.upgrade()).map(|p| p.borrow().key.clone());
            left_child = n.left_child_node.clone();
            right_child = n.right_child_node.clone();
        }
        println!("  {} [label=\"\\N ({},{},{})\"];", key, lcc, rcc, depth);
        if let Some(pk) = parent_key {
            println!("  {} -> {} [color=green];", key, pk);
        }
        if let Some(ref left) = left_child {
            println!("  {} -> {}", key, left.borrow().key);
            Self::print_helper(left);
        }
        if let Some(ref right) = right_child {
            println!("  {} -> {}", key, right.borrow().key);
            Self::print_helper(right);
        }
    }
}

pub fn bostree_node_weak_ref(node: &Rc<RefCell<BOSNode>>) -> Rc<RefCell<BOSNode>> {
    node.borrow_mut().weak_ref_count += 1;
    Rc::clone(node)
}

pub fn bostree_next_node(node: &Rc<RefCell<BOSNode>>) -> Option<Rc<RefCell<BOSNode>>> {
    let right_child = node.borrow().right_child_node.clone();
    if let Some(ref right) = right_child {
        let mut current = Rc::clone(right);
        loop {
            let left_child = current.borrow().left_child_node.clone();
            match left_child {
                Some(left) => current = left,
                None => return Some(current),
            }
        }
    } else {
        let mut current = Rc::clone(node);
        loop {
            let parent_weak = current.borrow().parent_node.clone();
            let parent = parent_weak.and_then(|p| p.upgrade());
            match parent {
                Some(p) => {
                    let is_right;
                    {
                        let pb = p.borrow();
                        is_right = pb.right_child_node.as_ref().map_or(false, |r| Rc::ptr_eq(r, &current));
                    }
                    if is_right {
                        current = p;
                    } else {
                        return Some(p);
                    }
                }
                None => return None,
            }
        }
    }
}

pub fn bostree_previous_node(node: &Rc<RefCell<BOSNode>>) -> Option<Rc<RefCell<BOSNode>>> {
    let left_child = node.borrow().left_child_node.clone();
    if let Some(ref left) = left_child {
        let mut current = Rc::clone(left);
        loop {
            let right_child = current.borrow().right_child_node.clone();
            match right_child {
                Some(right) => current = right,
                None => return Some(current),
            }
        }
    } else {
        let mut current = Rc::clone(node);
        loop {
            let parent_weak = current.borrow().parent_node.clone();
            let parent = parent_weak.and_then(|p| p.upgrade());
            match parent {
                Some(p) => {
                    let is_left;
                    {
                        let pb = p.borrow();
                        is_left = pb.left_child_node.as_ref().map_or(false, |l| Rc::ptr_eq(l, &current));
                    }
                    if is_left {
                        current = p;
                    } else {
                        return Some(p);
                    }
                }
                None => return None,
            }
        }
    }
}

pub fn bostree_rank(node: &Rc<RefCell<BOSNode>>) -> u32 {
    let mut counter = node.borrow().left_child_count;
    let mut current = Rc::clone(node);
    loop {
        let parent_weak = current.borrow().parent_node.clone();
        let parent = parent_weak.and_then(|p| p.upgrade());
        match parent {
            Some(p) => {
                let is_right;
                let left_count;
                {
                    let pb = p.borrow();
                    is_right = pb.right_child_node.as_ref().map_or(false, |r| Rc::ptr_eq(r, &current));
                    left_count = pb.left_child_count;
                }
                if is_right {
                    counter += 1 + left_count;
                }
                current = p;
            }
            None => return counter,
        }
    }
}
