use std::cell::RefCell;
use std::mem;
use std::rc::{Rc, Weak};

/// The tree structure.
#[derive(Debug)]
pub struct BOSTree {
    pub root_node: Option<Rc<RefCell<BOSNode>>>,
    pub cmp_function: BOSTreeCmpFunction,
    pub free_function: Option<BOSTreeFreeFunction>,
}

/// The node structure.
#[derive(Debug)]
pub struct BOSNode {
    pub left_child_count: u32,
    pub right_child_count: u32,
    pub depth: u32,
    pub left_child_node: Option<Rc<RefCell<BOSNode>>>,
    pub right_child_node: Option<Rc<RefCell<BOSNode>>>,
    pub parent_node: Option<Weak<RefCell<BOSNode>>>,
    pub key: String,
    pub data: Option<String>,
    pub weak_ref_count: u8,
    pub weak_ref_node_valid: u8,
}

pub type BOSTreeCmpFunction = fn(&str, &str) -> i32;
pub type BOSTreeFreeFunction = fn(&Rc<RefCell<BOSNode>>);

fn imax(a: u32, b: u32) -> u32 {
    if a > b { a } else { b }
}

fn child_depth(node: &Option<Rc<RefCell<BOSNode>>>) -> u32 {
    match node {
        Some(child) => child.borrow().depth + 1,
        None => 0,
    }
}

impl BOSTree {
    pub fn bostree_new(
        cmp_function: BOSTreeCmpFunction,
        free_function: Option<BOSTreeFreeFunction>,
    ) -> Self {
        BOSTree {
            root_node: None,
            cmp_function,
            free_function,
        }
    }

    pub fn bostree_node_count(&self) -> u32 {
        match self.root_node.as_ref() {
            Some(root) => {
                let r = root.borrow();
                r.left_child_count + r.right_child_count + 1
            }
            None => 0,
        }
    }

    pub fn bostree_insert(&mut self, key: String, data: Option<String>) -> Rc<RefCell<BOSNode>> {
        let new_node = Rc::new(RefCell::new(BOSNode {
            left_child_count: 0,
            right_child_count: 0,
            depth: 0,
            left_child_node: None,
            right_child_node: None,
            parent_node: None,
            key,
            data,
            weak_ref_count: 1,
            weak_ref_node_valid: 1,
        }));

        if self.root_node.is_none() {
            self.root_node = Some(Rc::clone(&new_node));
            return new_node;
        }

        let mut node = Rc::clone(self.root_node.as_ref().unwrap());

        loop {
            let cmp_result = (self.cmp_function)(&new_node.borrow().key, &node.borrow().key);
            let next_child;
            if cmp_result < 0 {
                node.borrow_mut().left_child_count += 1;
                next_child = node.borrow().left_child_node.clone();
            } else {
                node.borrow_mut().right_child_count += 1;
                next_child = node.borrow().right_child_node.clone();
            }
            match next_child {
                Some(child) => node = child,
                None => {
                    new_node.borrow_mut().parent_node = Some(Rc::downgrade(&node));
                    if cmp_result < 0 {
                        node.borrow_mut().left_child_node = Some(Rc::clone(&new_node));
                    } else {
                        node.borrow_mut().right_child_node = Some(Rc::clone(&new_node));
                    }
                    break;
                }
            }
        }

        // Walk back up to fix balance
        loop {
            self.fix_balance_and_update_root(&node);
            let parent_weak = node.borrow().parent_node.clone();
            match parent_weak.and_then(|p| p.upgrade()) {
                Some(parent) => node = parent,
                None => break,
            }
        }

        new_node
    }

    pub fn bostree_remove(&mut self, node: &Rc<RefCell<BOSNode>>) {
        let has_left = node.borrow().left_child_node.is_some();
        let has_right = node.borrow().right_child_node.is_some();

        // Node that we'll actually detach and bubble up from
        let detach_node;
        let bubble_start;

        if has_left && has_right {
            // Two-child case: find in-order predecessor
            let mut candidate = Rc::clone(node.borrow().left_child_node.as_ref().unwrap());
            loop {
                let next = candidate.borrow().right_child_node.clone();
                match next {
                    Some(right) => candidate = right,
                    None => break,
                }
            }

            // Swap key and data between node and candidate
            {
                let mut node_borrow = node.borrow_mut();
                let mut candidate_borrow = candidate.borrow_mut();
                mem::swap(&mut node_borrow.key, &mut candidate_borrow.key);
                mem::swap(&mut node_borrow.data, &mut candidate_borrow.data);
            }

            // Now we need to remove candidate from the tree
            // candidate has at most one child (it's the rightmost in its subtree)
            detach_node = candidate.clone();

            // Candidate's left child (candidate has no right child since it's rightmost)
            let candidate_left = candidate.borrow().left_child_node.clone();
            let candidate_parent_weak = candidate.borrow().parent_node.clone();
            let candidate_parent = candidate_parent_weak.as_ref().and_then(|w| w.upgrade());

            // If candidate is not the direct left child of node, we need to update counts
            // from candidate's parent up to node
            let is_direct_child = match &candidate_parent {
                Some(p) => Rc::ptr_eq(p, node),
                None => false,
            };

            // Replace candidate with its left child
            if let Some(ref left) = candidate_left {
                left.borrow_mut().parent_node = candidate_parent_weak.clone();
            }

            // Update candidate's parent's child pointer
            if let Some(ref p) = candidate_parent {
                if is_direct_child {
                    // candidate was left child of node
                    p.borrow_mut().left_child_node = candidate_left;
                } else {
                    // candidate was right child of some other node
                    p.borrow_mut().right_child_node = candidate_left;
                }
            }

            // Detach candidate
            candidate.borrow_mut().parent_node = None;
            candidate.borrow_mut().left_child_node = None;

            // Bubble start from candidate's parent
            bubble_start = candidate_parent;
        } else {
            // One-child or leaf case
            detach_node = node.clone();

            let replacement = if let Some(ref left) = node.borrow().left_child_node {
                Some(Rc::clone(left))
            } else if let Some(ref right) = node.borrow().right_child_node {
                Some(Rc::clone(right))
            } else {
                None
            };

            let node_parent_weak = node.borrow().parent_node.clone();
            let parent = node_parent_weak.as_ref().and_then(|w| w.upgrade());

            // Update replacement's parent
            if let Some(ref repl) = replacement {
                repl.borrow_mut().parent_node = node_parent_weak.clone();
            }

            // Update parent's child pointer
            if let Some(ref p) = parent {
                let is_left = Rc::ptr_eq(p.borrow().left_child_node.as_ref().unwrap(), node);
                if is_left {
                    p.borrow_mut().left_child_node = replacement;
                } else {
                    p.borrow_mut().right_child_node = replacement;
                }
            } else {
                // Node was root
                self.root_node = replacement;
            }

            // Detach node
            node.borrow_mut().parent_node = None;
            node.borrow_mut().left_child_node = None;
            node.borrow_mut().right_child_node = None;

            bubble_start = parent;
        }

        // Now bubble up from bubble_start, updating child counts, depths, and balance
        let mut bubble_up = bubble_start;
        while let Some(current) = bubble_up {
            // First, decrement parent's child count for current
            let parent_weak = current.borrow().parent_node.clone();
            if let Some(ref p) = parent_weak.as_ref().and_then(|w| w.upgrade()) {
                let is_left = Rc::ptr_eq(p.borrow().left_child_node.as_ref().unwrap(), &current);
                if is_left {
                    p.borrow_mut().left_child_count -= 1;
                } else {
                    p.borrow_mut().right_child_count -= 1;
                }
            }

            // Fix balance and update root
            self.fix_balance_and_update_root(&current);

            bubble_up = parent_weak.and_then(|w| w.upgrade());
        }

        // Mark node as invalid and decrement weak ref count
        detach_node.borrow_mut().weak_ref_node_valid = 0;
        detach_node.borrow_mut().weak_ref_count -= 1;
    }

    fn fix_balance_and_update_root(&mut self, node: &Rc<RefCell<BOSNode>>) {
        // Compute depths from children
        let left_child = node.borrow().left_child_node.clone();
        let right_child = node.borrow().right_child_node.clone();
        let ld = child_depth(&left_child);
        let rd = child_depth(&right_child);

        node.borrow_mut().depth = imax(ld, rd);

        let balance = rd as i32 - ld as i32;

        let result;
        if balance > 1 {
            // Right-heavy
            let right = right_child.as_ref().unwrap();
            let rc_left = right.borrow().left_child_node.clone();
            let rc_right = right.borrow().right_child_node.clone();
            let rld = child_depth(&rc_left);
            let rrd = child_depth(&rc_right);
            let right_balance = rrd as i32 - rld as i32;
            if right_balance < 0 {
                self.bostree_rotate_right(right);
            }
            result = self.bostree_rotate_left(node);
        } else if balance < -1 {
            // Left-heavy
            let left = left_child.as_ref().unwrap();
            let lc_left = left.borrow().left_child_node.clone();
            let lc_right = left.borrow().right_child_node.clone();
            let lld = child_depth(&lc_left);
            let lrd = child_depth(&lc_right);
            let left_balance = lrd as i32 - lld as i32;
            if left_balance > 0 {
                self.bostree_rotate_left(left);
            }
            result = self.bostree_rotate_right(node);
        } else {
            result = Rc::clone(node);
        }

        // Update root if necessary
        if result.borrow().parent_node.is_none() {
            self.root_node = Some(result);
        }
    }

    fn bostree_rotate_left(&self, p: &Rc<RefCell<BOSNode>>) -> Rc<RefCell<BOSNode>> {
        let r;
        let parent_weak;
        {
            let pb = p.borrow();
            r = Rc::clone(pb.right_child_node.as_ref().unwrap());
            parent_weak = pb.parent_node.clone();
        }

        // Update parent's child pointer
        if let Some(parent_rc) = parent_weak.as_ref().and_then(|w| w.upgrade()) {
            let is_left;
            {
                let prb = parent_rc.borrow();
                is_left = Rc::ptr_eq(prb.left_child_node.as_ref().unwrap(), p);
            }
            if is_left {
                parent_rc.borrow_mut().left_child_node = Some(Rc::clone(&r));
            } else {
                parent_rc.borrow_mut().right_child_node = Some(Rc::clone(&r));
            }
        }

        r.borrow_mut().parent_node = parent_weak;

        // Move R's left child to P's right
        let r_left;
        let r_left_count;
        {
            let r_borrow = r.borrow();
            r_left = r_borrow.left_child_node.clone();
            r_left_count = r_borrow.left_child_count;
        }
        p.borrow_mut().right_child_node = r_left;
        p.borrow_mut().right_child_count = r_left_count;

        {
            let right_child = p.borrow().right_child_node.clone();
            if let Some(ref rc) = right_child {
                rc.borrow_mut().parent_node = Some(Rc::downgrade(p));
            }
        }

        // Update P's depth
        {
            let left_child = p.borrow().left_child_node.clone();
            let right_child = p.borrow().right_child_node.clone();
            let pld = child_depth(&left_child);
            let prd = child_depth(&right_child);
            p.borrow_mut().depth = imax(pld, prd);
        }
        p.borrow_mut().parent_node = Some(Rc::downgrade(&r));

        // Set R's left child to P
        r.borrow_mut().left_child_node = Some(Rc::clone(p));
        {
            let left_count = p.borrow().left_child_count;
            let right_count = p.borrow().right_child_count;
            r.borrow_mut().left_child_count = left_count + right_count + 1;
        }
        {
            let left_child = r.borrow().left_child_node.clone();
            let right_child = r.borrow().right_child_node.clone();
            let rld = child_depth(&left_child);
            let rrd = child_depth(&right_child);
            r.borrow_mut().depth = imax(rld, rrd);
        }

        r
    }

    fn bostree_rotate_right(&self, p: &Rc<RefCell<BOSNode>>) -> Rc<RefCell<BOSNode>> {
        let l;
        let parent_weak;
        {
            let pb = p.borrow();
            l = Rc::clone(pb.left_child_node.as_ref().unwrap());
            parent_weak = pb.parent_node.clone();
        }

        if let Some(parent_rc) = parent_weak.as_ref().and_then(|w| w.upgrade()) {
            let is_left;
            {
                let prb = parent_rc.borrow();
                is_left = Rc::ptr_eq(prb.left_child_node.as_ref().unwrap(), p);
            }
            if is_left {
                parent_rc.borrow_mut().left_child_node = Some(Rc::clone(&l));
            } else {
                parent_rc.borrow_mut().right_child_node = Some(Rc::clone(&l));
            }
        }

        l.borrow_mut().parent_node = parent_weak;

        let l_right;
        let l_right_count;
        {
            let l_borrow = l.borrow();
            l_right = l_borrow.right_child_node.clone();
            l_right_count = l_borrow.right_child_count;
        }
        p.borrow_mut().left_child_node = l_right;
        p.borrow_mut().left_child_count = l_right_count;

        {
            let left_child = p.borrow().left_child_node.clone();
            if let Some(ref rc) = left_child {
                rc.borrow_mut().parent_node = Some(Rc::downgrade(p));
            }
        }

        {
            let left_child = p.borrow().left_child_node.clone();
            let right_child = p.borrow().right_child_node.clone();
            let pld = child_depth(&left_child);
            let prd = child_depth(&right_child);
            p.borrow_mut().depth = imax(pld, prd);
        }
        p.borrow_mut().parent_node = Some(Rc::downgrade(&l));

        l.borrow_mut().right_child_node = Some(Rc::clone(p));
        {
            let left_count = p.borrow().left_child_count;
            let right_count = p.borrow().right_child_count;
            l.borrow_mut().right_child_count = left_count + right_count + 1;
        }
        {
            let left_child = l.borrow().left_child_node.clone();
            let right_child = l.borrow().right_child_node.clone();
            let lld = child_depth(&left_child);
            let lrd = child_depth(&right_child);
            l.borrow_mut().depth = imax(lld, lrd);
