    node.borrow_mut().weak_ref_count += 1;
    Rc::clone(node)
}

pub fn bostree_next_node(node: &Rc<RefCell<BOSNode>>) -> Option<Rc<RefCell<BOSNode>>> {
    let right_child = node.borrow().right_child_node.clone();
    if let Some(ref right) = right_child {
        let mut current = Rc::clone(right);
        loop {
            let left_child = current.borrow().left_child_node.clone();
            match left_child {
                Some(left) => current = left,
                None => return Some(current),
            }
        }
    } else {
        let mut current = Rc::clone(node);
        loop {
            let parent_weak = current.borrow().parent_node.clone();
            let parent = parent_weak.and_then(|p| p.upgrade());
            match parent {
                Some(p) => {
                    let is_right;
                    {
                        let pb = p.borrow();
                        is_right = pb.right_child_node.as_ref().map_or(false, |r| Rc::ptr_eq(r, &current));
                    }
                    if is_right {
                        current = p;
                    } else {
                        return Some(p);
                    }
                }
                None => return None,
            }
        }
    }
}

pub fn bostree_previous_node(node: &Rc<RefCell<BOSNode>>) -> Option<Rc<RefCell<BOSNode>>> {
    let left_child = node.borrow().left_child_node.clone();
    if let Some(ref left) = left_child {
        let mut current = Rc::clone(left);
        loop {
            let right_child = current.borrow().right_child_node.clone();
            match right_child {
                Some(right) => current = right,
                None => return Some(current),
            }
        }
    } else {
        let mut current = Rc::clone(node);
        loop {
            let parent_weak = current.borrow().parent_node.clone();
            let parent = parent_weak.and_then(|p| p.upgrade());
            match parent {
                Some(p) => {
                    let is_left;
                    {
                        let pb = p.borrow();
                        is_left = pb.left_child_node.as_ref().map_or(false, |l| Rc::ptr_eq(l, &current));
                    }
                    if is_left {
                        current = p;
                    } else {
                        return Some(p);
                    }
                }
                None => return None,
            }
        }
    }
}

pub fn bostree_rank(node: &Rc<RefCell<BOSNode>>) -> u32 {
    let mut counter = node.borrow().left_child_count;
    let mut current = Rc::clone(node);
    loop {
        let parent_weak = current.borrow().parent_node.clone();
        let parent = parent_weak.and_then(|p| p.upgrade());
        match parent {
            Some(p) => {
                let is_right;
                let left_count;
                {
                    let pb = p.borrow();
                    is_right = pb.right_child_node.as_ref().map_or(false, |r| Rc::ptr_eq(r, &current));
                    left_count = pb.left_child_count;
                }
                if is_right {
                    counter += 1 + left_count;
                }
                current = p;
            }
            None => return counter,
        }
    }
}
