    let mut counter = node.borrow().left_child_count;
    let mut current = Rc::clone(node);
    loop {
        let parent_weak = current.borrow().parent_node.clone();
        let parent = parent_weak.and_then(|p| p.upgrade());
        match parent {
            Some(p) => {
                let is_right;
