                    // Fix depth and balance
                    let left = cur.borrow().left_child_node.clone();
                    let right = cur.borrow().right_child_node.clone();
                    cur.borrow_mut().depth = imax(get_child_depth(&left), get_child_depth(&right));
                    let balance = get_child_depth(&right) as i32 - get_child_depth(&left) as i32;
                    if balance > 1 {
                        let r = right.as_ref().unwrap();
                        let rb = get_child_depth(&r.borrow().right_child_node) as i32 - get_child_depth(&r.borrow().left_child_node) as i32;
                        if rb < 0 {
                            self.rotate_right(r);
                        }
                        up = Some(self.rotate_left(&cur));
                    } else if balance < -1 {
                        let l = left.as_ref().unwrap();
                        let lb = get_child_depth(&l.borrow().right_child_node) as i32 - get_child_depth(&l.borrow().left_child_node) as i32;
                        if lb > 0 {
                            self.rotate_left(l);
                        }
                        up = Some(self.rotate_right(&cur));
                    } else {
                        up = cur.borrow().parent_node.as_ref().and_then(|w| w.upgrade());
                    }
                }
            }

            // Fix pred's depth
            let left = pred.borrow().left_child_node.clone();
            let right = pred.borrow().right_child_node.clone();
            pred.borrow_mut().depth = imax(get_child_depth(&left), get_child_depth(&right));

            // Now walk up from pred to root, decrementing child counts
            let mut up = pred.borrow().parent_node.as_ref().and_then(|w| w.upgrade());
            while let Some(cur) = up {
                // Decrement parent's child count for cur
                let parent_weak = cur.borrow().parent_node.clone();
                if let Some(ref p) = parent_weak.as_ref().and_then(|w| w.upgrade()) {
                    if p.borrow().left_child_node.as_ref().map_or(false, |l| Rc::ptr_eq(l, &cur)) {
                        p.borrow_mut().left_child_count -= 1;
                    } else {
                        p.borrow_mut().right_child_count -= 1;
                    }
                }

                // Fix depth and balance
                let left = cur.borrow().left_child_node.clone();
                let right = cur.borrow().right_child_node.clone();
                cur.borrow_mut().depth = imax(get_child_depth(&left), get_child_depth(&right));
                let balance = get_child_depth(&right) as i32 - get_child_depth(&left) as i32;
                if balance > 1 {
                    let r = right.as_ref().unwrap();
                    let rb = get_child_depth(&r.borrow().right_child_node) as i32 - get_child_depth(&r.borrow().left_child_node) as i32;
                    if rb < 0 {
                        self.rotate_right(r);
                    }
                    up = Some(self.rotate_left(&cur));
                    // After rotation, decrement the new parent's count for the rotated node
                    if let Some(ref p) = up.as_ref().unwrap().borrow().parent_node.as_ref().and_then(|w| w.upgrade()) {
                        if p.borrow().left_child_node.as_ref().map_or(false, |l| Rc::ptr_eq(l, up.as_ref().unwrap())) {
                            p.borrow_mut().left_child_count -= 1;
                        } else {
                            p.borrow_mut().right_child_count -= 1;
                        }
                    }
                } else if balance < -1 {
                    let l = left.as_ref().unwrap();
                    let lb = get_child_depth(&l.borrow().right_child_node) as i32 - get_child_depth(&l.borrow().left_child_node) as i32;
                    if lb > 0 {
                        self.rotate_left(l);
                    }
                    up = Some(self.rotate_right(&cur));
                    if let Some(ref p) = up.as_ref().unwrap().borrow().parent_node.as_ref().and_then(|w| w.upgrade()) {
                        if p.borrow().left_child_node.as_ref().map_or(false, |l| Rc::ptr_eq(l, up.as_ref().unwrap())) {
                            p.borrow_mut().left_child_count -= 1;
                        } else {
                            p.borrow_mut().right_child_count -= 1;
                        }
                    }
                } else {
                    up = parent_weak.and_then(|w| w.upgrade());
                }
            }

            // Update root
            self.update_root();

            // Mark node as invalid
            node.borrow_mut().weak_ref_node_valid = 0;
            node.borrow_mut().weak_ref_count -= 1;
        } else {
            // One child or leaf
            let replacement = node.borrow().left_child_node.clone()
                .or_else(|| node.borrow().right_child_node.clone());
            let parent_weak = node.borrow().parent_node.clone();
            let parent = parent_weak.as_ref().and_then(|w| w.upgrade());

            if let Some(ref repl) = replacement {
                repl.borrow_mut().parent_node = parent_weak.clone();
            }

            if let Some(ref p) = parent {
                if p.borrow().left_child_node.as_ref().map_or(false, |l| Rc::ptr_eq(l, node)) {
                    p.borrow_mut().left_child_node = replacement;
                } else {
                    p.borrow_mut().right_child_node = replacement;
                }
            } else {
                self.root_node = replacement;
            }

            node.borrow_mut().parent_node = None;
            node.borrow_mut().left_child_node = None;
            node.borrow_mut().right_child_node = None;

            // Walk up from parent, decrementing counts and rebalancing
            let mut up = parent;
            while let Some(cur) = up {
                let parent_weak = cur.borrow().parent_node.clone();
                if let Some(ref p) = parent_weak.as_ref().and_then(|w| w.upgrade()) {
                    if p.borrow().left_child_node.as_ref().map_or(false, |l| Rc::ptr_eq(l, &cur)) {
                        p.borrow_mut().left_child_count -= 1;
