                let balance = get_child_depth(&right) as i32 - get_child_depth(&left) as i32;
                if balance > 1 {
                    let r = right.as_ref().unwrap();
                    let rb = get_child_depth(&r.borrow().right_child_node) as i32 - get_child_depth(&r.borrow().left_child_node) as i32;
                    if rb < 0 {
                        self.rotate_right(r);
                    }
                    up = Some(self.rotate_left(&cur));
                    if let Some(ref p) = up.as_ref().unwrap().borrow().parent_node.as_ref().and_then(|w| w.upgrade()) {
                        if p.borrow().left_child_node.as_ref().map_or(false, |l| Rc::ptr_eq(l, up.as_ref().unwrap())) {
                            p.borrow_mut().left_child_count -= 1;
                        } else {
                            p.borrow_mut().right_child_count -= 1;
                        }
                    }
                } else if balance < -1 {
                    let l = left.as_ref().unwrap();
                    let lb = get_child_depth(&l.borrow().right_child_node) as i32 - get_child_depth(&l.borrow().left_child_node) as i32;
                    if lb > 0 {
                        self.rotate_left(l);
                    }
                    up = Some(self.rotate_right(&cur));
                    if let Some(ref p) = up.as_ref().unwrap().borrow().parent_node.as_ref().and_then(|w| w.upgrade()) {
