                        } else {
                            p.borrow_mut().right_child_count -= 1;
                        }
                    }
                } else {
                    up = parent_weak.and_then(|w| w.upgrade());
                }
            }

            self.update_root();
            node.borrow_mut().weak_ref_node_valid = 0;
            node.borrow_mut().weak_ref_count -= 1;
        }
    }

    fn rebalance(&mut self, node: &Rc<RefCell<BOSNode>>) -> Option<Rc<RefCell<BOSNode>>> {
        let left = node.borrow().left_child_node.clone();
        let right = node.borrow().right_child_node.clone();
        node.borrow_mut().depth = imax(get_child_depth(&left), get_child_depth(&right));
        let balance = get_child_depth(&right) as i32 - get_child_depth(&left) as i32;
        if balance > 1 {
            let r = right.as_ref().unwrap();
            if get_child_depth(&r.borrow().right_child_node) as i32 - get_child_depth(&r.borrow().left_child_node) as i32 < 0 {
                self.rotate_right(r);
            }
            self.rotate_left(node).borrow().parent_node.as_ref().and_then(|w| w.upgrade())
        } else if balance < -1 {
            let l = left.as_ref().unwrap();
            if get_child_depth(&l.borrow().right_child_node) as i32 - get_child_depth(&l.borrow().left_child_node) as i32 > 0 {
                self.rotate_left(l);
            }
            self.rotate_right(node).borrow().parent_node.as_ref().and_then(|w| w.upgrade())
        } else {
            node.borrow().parent_node.as_ref().and_then(|w| w.upgrade())
        }
    }

    fn rotate_left(&mut self, p: &Rc<RefCell<BOSNode>>) -> Rc<RefCell<BOSNode>> {
        let r;
        let parent_weak;
        {
            let pb = p.borrow();
            r = Rc::clone(pb.right_child_node.as_ref().unwrap());
            parent_weak = pb.parent_node.clone();
        }
        if let Some(ref parent_rc) = parent_weak.as_ref().and_then(|w| w.upgrade()) {
            if parent_rc.borrow().left_child_node.as_ref().map_or(false, |l| Rc::ptr_eq(l, p)) {
                parent_rc.borrow_mut().left_child_node = Some(Rc::clone(&r));
            } else {
                parent_rc.borrow_mut().right_child_node = Some(Rc::clone(&r));
            }
        } else {
            self.root_node = Some(Rc::clone(&r));
        }
        r.borrow_mut().parent_node = parent_weak;
        let r_left;
        let r_left_count;
        {
            let rb = r.borrow();
            r_left = rb.left_child_node.clone();
            r_left_count = rb.left_child_count;
        }
        p.borrow_mut().right_child_node = r_left;
        p.borrow_mut().right_child_count = r_left_count;
        if let Some(ref c) = p.borrow().right_child_node {
            c.borrow_mut().parent_node = Some(Rc::downgrade(p));
        }
        let ld = get_child_depth(&p.borrow().left_child_node);
        let rd = get_child_depth(&p.borrow().right_child_node);
        p.borrow_mut().depth = imax(ld, rd);
        p.borrow_mut().parent_node = Some(Rc::downgrade(&r));
        r.borrow_mut().left_child_node = Some(Rc::clone(p));
        r.borrow_mut().left_child_count = p.borrow().left_child_count + p.borrow().right_child_count + 1;
        let ld2 = get_child_depth(&r.borrow().left_child_node);
        let rd2 = get_child_depth(&r.borrow().right_child_node);
        r.borrow_mut().depth = imax(ld2, rd2);
        r
    }

    fn rotate_right(&mut self, p: &Rc<RefCell<BOSNode>>) -> Rc<RefCell<BOSNode>> {
        let l;
        let parent_weak;
        {
            let pb = p.borrow();
            l = Rc::clone(pb.left_child_node.as_ref().unwrap());
            parent_weak = pb.parent_node.clone();
        }
        if let Some(ref parent_rc) = parent_weak.as_ref().and_then(|w| w.upgrade()) {
            if parent_rc.borrow().left_child_node.as_ref().map_or(false, |l| Rc::ptr_eq(l, p)) {
                parent_rc.borrow_mut().left_child_node = Some(Rc::clone(&l));
            } else {
                parent_rc.borrow_mut().right_child_node = Some(Rc::clone(&l));
            }
        } else {
            self.root_node = Some(Rc::clone(&l));
        }
        l.borrow_mut().parent_node = parent_weak;
        let l_right;
        let l_right_count;
        {
            let lb = l.borrow();
            l_right = lb.right_child_node.clone();
            l_right_count = lb.right_child_count;
        }
        p.borrow_mut().left_child_node = l_right;
        p.borrow_mut().left_child_count = l_right_count;
        if let Some(ref c) = p.borrow().left_child_node {
            c.borrow_mut().parent_node = Some(Rc::downgrade(p));
        }
        let ld = get_child_depth(&p.borrow().left_child_node);
        let rd = get_child_depth(&p.borrow().right_child_node);
        p.borrow_mut().depth = imax(ld, rd);
        p.borrow_mut().parent_node = Some(Rc::downgrade(&l));
        l.borrow_mut().right_child_node = Some(Rc::clone(p));
        l.borrow_mut().right_child_count = p.borrow().left_child_count + p.borrow().right_child_count + 1;
        let ld2 = get_child_depth(&l.borrow().left_child_node);
        let rd2 = get_child_depth(&l.borrow().right_child_node);
        l.borrow_mut().depth = imax(ld2, rd2);
        l
    }

    fn update_root(&mut self) {
        if let Some(ref root) = self.root_node {
            let mut cur = Rc::clone(root);
            loop {
                let p = cur.borrow().parent_node.as_ref().and_then(|w| w.upgrade());
                match p {
                    Some(parent) => cur = parent,
                    None => break,
                }
            }
            self.root_node = Some(cur);
        }
    }

    pub fn bostree_node_weak_unref(&mut self, node: &Rc<RefCell<BOSNode>>) -> Option<Rc<RefCell<BOSNode>>> {
        node.borrow_mut().weak_ref_count -= 1;
        if node.borrow().weak_ref_count == 0 {
            if let Some(f) = self.free_function {
                f(node);
            }
            None
        } else if node.borrow().weak_ref_node_valid != 0 {
            Some(Rc::clone(node))
        } else {
            None
        }
    }

    pub fn bostree_lookup(&self, key: &str) -> Option<Rc<RefCell<BOSNode>>> {
        let mut cur = self.root_node.as_ref().map(Rc::clone);
        while let Some(node) = cur {
            let (cmp, next);
            {
                let nb = node.borrow();
                cmp = (self.cmp_function)(key, &nb.key);
                next = if cmp == 0 { None } else if cmp < 0 { nb.left_child_node.clone() } else { nb.right_child_node.clone() };
            }
            if cmp == 0 { return Some(node); }
            cur = next;
        }
        None
    }

    pub fn bostree_select(&self, index: u32) -> Option<Rc<RefCell<BOSNode>>> {
        let mut cur = self.root_node.as_ref().map(Rc::clone);
        let mut idx = index;
        while let Some(node) = cur {
            let (found, next);
            {
                let nb = node.borrow();
                if nb.left_child_count <= idx {
                    let rem = idx - nb.left_child_count;
                    if rem == 0 { (found, next) = (true, None); }
                    else { idx = rem - 1; (found, next) = (false, nb.right_child_node.clone()); }
                } else { (found, next) = (false, nb.left_child_node.clone()); }
            }
            if found { return Some(node); }
            cur = next;
        }
        None
    }

    #[cfg(debug_assertions)]
    pub fn bostree_print(&self) {
        if let Some(ref root) = self.root_node {
            println!("digraph {{\n  ordering = out;");
            Self::print_helper(root);
            println!("}}");
        }
    }
    #[cfg(debug_assertions)]
    fn print_helper(node: &Rc<RefCell<BOSNode>>) {
        let (key, lcc, rcc, depth, parent_key, left, right);
        {
            let n = node.borrow();
            key = n.key.clone(); lcc = n.left_child_count; rcc = n.right_child_count; depth = n.depth;
            parent_key = n.parent_node.as_ref().and_then(|p| p.upgrade()).map(|p| p.borrow().key.clone());
            left = n.left_child_node.clone(); right = n.right_child_node.clone();
        }
        println!("  {} [label=\"\\N ({},{},{})\"];", key, lcc, rcc, depth);
        if let Some(pk) = parent_key { println!("  {} -> {} [color=green];", key, pk); }
        if let Some(ref l) = left { println!("  {} -> {}", key, l.borrow().key); Self::print_helper(l); }
        if let Some(ref r) = right { println!("  {} -> {}", key, r.borrow().key); Self::print_helper(r); }
    }
}

pub fn bostree_node_weak_ref(node: &Rc<RefCell<BOSNode>>) -> Rc<RefCell<BOSNode>> {
    node.borrow_mut().weak_ref_count += 1;
    Rc::clone(node)
}

pub fn bostree_next_node(node: &Rc<RefCell<BOSNode>>) -> Option<Rc<RefCell<BOSNode>>> {
    if let Some(ref right) = node.borrow().right_child_node {
        let mut cur = Rc::clone(right);
        while cur.borrow().left_child_node.is_some() {
            let next = Rc::clone(cur.borrow().left_child_node.as_ref().unwrap());
            cur = next;
        }
        Some(cur)
    } else {
        let mut cur = Rc::clone(node);
        loop {
            let p = cur.borrow().parent_node.as_ref().and_then(|w| w.upgrade());
            match p {
                Some(parent) => {
                    let is_right = parent.borrow().right_child_node.as_ref().map_or(false, |r| Rc::ptr_eq(r, &cur));
                    if is_right { cur = parent; } else { return Some(parent); }
                }
                None => return None,
            }
        }
    }
}

pub fn bostree_previous_node(node: &Rc<RefCell<BOSNode>>) -> Option<Rc<RefCell<BOSNode>>> {
    if let Some(ref left) = node.borrow().left_child_node {
        let mut cur = Rc::clone(left);
        while cur.borrow().right_child_node.is_some() {
            let next = Rc::clone(cur.borrow().right_child_node.as_ref().unwrap());
            cur = next;
        }
        Some(cur)
    } else {
        let mut cur = Rc::clone(node);
        loop {
            let p = cur.borrow().parent_node.as_ref().and_then(|w| w.upgrade());
            match p {
                Some(parent) => {
                    let is_left = parent.borrow().left_child_node.as_ref().map_or(false, |l| Rc::ptr_eq(l, &cur));
                    if is_left { cur = parent; } else { return Some(parent); }
                }
                None => return None,
            }
        }
    }
}

pub fn bostree_rank(node: &Rc<RefCell<BOSNode>>) -> u32 {
    let mut counter = node.borrow().left_child_count;
    let mut cur = Rc::clone(node);
    loop {
        let p = cur.borrow().parent_node.as_ref().and_then(|w| w.upgrade());
        match p {
            Some(parent) => {
                if parent.borrow().right_child_node.as_ref().map_or(false, |r| Rc::ptr_eq(r, &cur)) {
                    counter += 1 + parent.borrow().left_child_count;
                }
                cur = parent;
            }
            None => return counter,
        }
    }
}
