    } else {
        let mut cur = Rc::clone(node);
        loop { let p = cur.borrow().parent_node.as_ref().and_then(|w| w.upgrade()); match p { Some(parent) => { if parent.borrow().left_child_node.as_ref().map_or(false, |l| Rc::ptr_eq(l, &cur)) { cur = parent; } else { return Some(parent); } } None => return None, } }
    }
}

pub fn bostree_rank(node: &Rc<RefCell<BOSNode>>) -> u32 {
    let mut counter = node.borrow().left_child_count;
    let mut cur = Rc::clone(node);
    loop { let p = cur.borrow().parent_node.as_ref().and_then(|w| w.upgrade()); match p { Some(parent) => { if parent.borrow().right_child_node.as_ref().map_or(false, |r| Rc::ptr_eq(r, &cur)) { counter += 1 + parent.borrow().left_child_count; } cur = parent; } None => return counter, } }
}
