    pub fn bostree_new(cmp: BOSTreeCmpFunction, free_fn: Option<BOSTreeFreeFunction>) -> Self {
        BOSTree { root_node: None, cmp_function: cmp, free_function: free_fn }
    }

    pub fn bostree_node_count(&self) -> u32 {
        self.root_node.as_ref().map_or(0, |r| {
            let n = r.borrow();
            n.left_child_count + n.right_child_count + 1
        })
    }

    pub fn bostree_insert(&mut self, key: String, data: Option<String>) -> Rc<RefCell<BOSNode>> {
        let node = Rc::new(RefCell::new(BOSNode {
            left_child_count: 0, right_child_count: 0, depth: 0,
            left_child_node: None, right_child_node: None, parent_node: None,
            key, data, weak_ref_count: 1, weak_ref_node_valid: 1,
        }));
        if self.root_node.is_none() {
            self.root_node = Some(Rc::clone(&node));
            return node;
        }
        let mut cur = Rc::clone(self.root_node.as_ref().unwrap());
        loop {
            let cmp = (self.cmp_function)(&node.borrow().key, &cur.borrow().key);
            let next;
            if cmp < 0 {
                cur.borrow_mut().left_child_count += 1;
                next = cur.borrow().left_child_node.clone();
            } else {
                cur.borrow_mut().right_child_count += 1;
                next = cur.borrow().right_child_node.clone();
            }
            match next {
                Some(child) => cur = child,
                None => {
                    node.borrow_mut().parent_node = Some(Rc::downgrade(&cur));
                    if cmp < 0 {
                        cur.borrow_mut().left_child_node = Some(Rc::clone(&node));
                    } else {
                        cur.borrow_mut().right_child_node = Some(Rc::clone(&node));
                    }
                    break;
                }
            }
        }
        let mut up = Some(cur);
        while let Some(n) = up {
            up = self.rebalance(&n);
        }
        node
