    pub fn bostree_remove(&mut self, node: &Rc<RefCell<BOSNode>>) {
        let has_left = node.borrow().left_child_node.is_some();
        let has_right = node.borrow().right_child_node.is_some();

        if has_left && has_right {
            // Find predecessor (rightmost in left subtree)
            let mut pred = Rc::clone(node.borrow().left_child_node.as_ref().unwrap());
            while pred.borrow().right_child_node.is_some() {
                let next = Rc::clone(pred.borrow().right_child_node.as_ref().unwrap());
                pred = next;
            }
            // Swap key and data
            {
                let mut nb = node.borrow_mut();
                let mut pb = pred.borrow_mut();
                mem::swap(&mut nb.key, &mut pb.key);
                mem::swap(&mut nb.data, &mut pb.data);
            }
