    pub fn bostree_lookup(&self, key: &str) -> Option<Rc<RefCell<BOSNode>>> {
        let mut cur = self.root_node.as_ref().map(Rc::clone);
        while let Some(node) = cur {
            let cmp;
            let next;
            {
                let nb = node.borrow();
                cmp = (self.cmp_function)(key, &nb.key);
                next = if cmp == 0 { None } else if cmp < 0 { nb.left_child_node.clone() } else { nb.right_child_node.clone() };
            }
            if cmp == 0 { return Some(node); }
            cur = next;
        }
        None
    }

    pub fn bostree_select(&self, index: u32) -> Option<Rc<RefCell<BOSNode>>> {
        let mut cur = self.root_node.as_ref().map(Rc::clone);
        let mut idx = index;
        while let Some(node) = cur {
            let found;
            let next;
            {
                let nb = node.borrow();
                if nb.left_child_count <= idx {
                    let rem = idx - nb.left_child_count;
                    if rem == 0 { (found, next) = (true, None); }
                    else { idx = rem - 1; (found, next) = (false, nb.right_child_node.clone()); }
                } else { (found, next) = (false, nb.left_child_node.clone()); }
            }
            if found { return Some(node); }
            cur = next;
        }
        None
    }

