    pub right_child_node: Option<Rc<RefCell<BOSNode>>>,
    pub parent_node: Option<Weak<RefCell<BOSNode>>>,
    pub key: String,
    pub data: Option<String>,
    pub weak_ref_count: u8,
    pub weak_ref_node_valid: u8,
}

pub type BOSTreeCmpFunction = fn(&str, &str) -> i32;
pub type BOSTreeFreeFunction = fn(&Rc<RefCell<BOSNode>>);

fn imax(a: u32, b: u32) -> u32 { if a > b { a } else { b } }

fn child_depth(n: &Option<Rc<RefCell<BOSNode>>>) -> u32 {
    n.as_ref().map_or(0, |c| c.borrow().depth + 1)
}

impl BOSTree {
    pub fn bostree_new(cmp: BOSTreeCmpFunction, free_fn: Option<BOSTreeFreeFunction>) -> Self {
        BOSTree { root_node: None, cmp_function: cmp, free_function: free_fn }
    }

    pub fn bostree_node_count(&self) -> u32 {
        self.root_node.as_ref().map_or(0, |r| {
            let n = r.borrow();
            n.left_child_count + n.right_child_count + 1
        })
    }

    pub fn bostree_insert(&mut self, key: String, data: Option<String>) -> Rc<RefCell<BOSNode>> {
        let node = Rc::new(RefCell::new(BOSNode {
            left_child_count: 0, right_child_count: 0, depth: 0,
            left_child_node: None, right_child_node: None, parent_node: None,
            key, data, weak_ref_count: 1, weak_ref_node_valid: 1,
        }));
        if self.root_node.is_none() {
            self.root_node = Some(Rc::clone(&node));
            return node;
        }
        let mut cur = Rc::clone(self.root_node.as_ref().unwrap());
        loop {
            let cmp = (self.cmp_function)(&node.borrow().key, &cur.borrow().key);
            let next;
            if cmp < 0 {
                cur.borrow_mut().left_child_count += 1;
                next = cur.borrow().left_child_node.clone();
            } else {
                cur.borrow_mut().right_child_count += 1;
                next = cur.borrow().right_child_node.clone();
            }
            match next {
                Some(child) => cur = child,
                None => {
                    node.borrow_mut().parent_node = Some(Rc::downgrade(&cur));
                    if cmp < 0 {
                        cur.borrow_mut().left_child_node = Some(Rc::clone(&node));
                    } else {
                        cur.borrow_mut().right_child_node = Some(Rc::clone(&node));
                    }
                    break;
                }
            }
        }
        let mut up = Some(cur);
        while let Some(n) = up {
            up = self.rebalance(&n);
        }
        node
    }

    pub fn bostree_remove(&mut self, node: &Rc<RefCell<BOSNode>>) {
        let has_left = node.borrow().left_child_node.is_some();
        let has_right = node.borrow().right_child_node.is_some();

        // Node that we'll actually detach
        let detach_node;
        // Where to start the walk-up for count decrements
        let bubble_start;

        if has_left && has_right {
            // Two-child case: find predecessor (rightmost in left subtree)
            let mut candidate = Rc::clone(node.borrow().left_child_node.as_ref().unwrap());
            while candidate.borrow().right_child_node.is_some() {
                let next = Rc::clone(candidate.borrow().right_child_node.as_ref().unwrap());
                candidate = next;
            }
            // Swap key and data
            {
                let mut nb = node.borrow_mut();
                let mut cb = candidate.borrow_mut();
                mem::swap(&mut nb.key, &mut cb.key);
                mem::swap(&mut nb.data, &mut cb.data);
            }
            // Now remove candidate (which has at most one child - the left one)
            detach_node = candidate.clone();
            let candidate_parent_weak = candidate.borrow().parent_node.clone();
            let candidate_parent = candidate_parent_weak.as_ref().and_then(|w| w.upgrade());
            let candidate_left = candidate.borrow().left_child_node.clone();
            // Replace candidate with its left child
            if let Some(ref left) = candidate_left {
                left.borrow_mut().parent_node = candidate_parent_weak.clone();
            }
            // Update candidate's parent's child pointer
            if let Some(ref p) = candidate_parent {
                let is_candidate_left;
                {
                    let pb = p.borrow();
                    is_candidate_left = pb.left_child_node.as_ref().map_or(false, |l| Rc::ptr_eq(l, &candidate));
                }
                if is_candidate_left {
                    p.borrow_mut().left_child_node = candidate_left;
                } else {
                    p.borrow_mut().right_child_node = candidate_left;
                }
            }
            // Detach candidate
            candidate.borrow_mut().parent_node = None;
            candidate.borrow_mut().left_child_node = None;
            // Fix immediate parent node child count
            if let Some(ref p) = candidate_parent {
                let is_candidate_left;
                {
                    let pb = p.borrow();
                    is_candidate_left = pb.left_child_node.as_ref().map_or(false, |l| Rc::ptr_eq(l, &candidate));
                }
                if is_candidate_left {
                    p.borrow_mut().left_child_count -= 1;
                } else {
                    p.borrow_mut().right_child_count -= 1;
                }
            }
            // Walk up from candidate's parent to root
            bubble_start = candidate_parent;
        } else {
            // One child or leaf
            detach_node = node.clone();
            let replacement;
            let parent_weak;
            let parent;
            {
                let nb = node.borrow();
                replacement = nb.left_child_node.clone().or_else(|| nb.right_child_node.clone());
                parent_weak = nb.parent_node.clone();
                parent = parent_weak.as_ref().and_then(|w| w.upgrade());
            }
            // Update replacement's parent
            if let Some(ref repl) = replacement {
                repl.borrow_mut().parent_node = parent_weak.clone();
            }
            // Update parent's child pointer
            if let Some(ref p) = parent {
                let is_left;
                {
                    let pb = p.borrow();
                    is_left = pb.left_child_node.as_ref().map_or(false, |l| Rc::ptr_eq(l, node));
                }
                if is_left {
                    p.borrow_mut().left_child_node = replacement;
                } else {
                    p.borrow_mut().right_child_node = replacement;
                }
            } else {
                self.root_node = replacement;
            }
            // Detach node
            node.borrow_mut().parent_node = None;
            node.borrow_mut().left_child_node = None;
            node.borrow_mut().right_child_node = None;
            bubble_start = parent;
        }

        // Walk up from bubble_start, decrementing child counts and rebalancing
        let mut bubble_up = bubble_start;
        while let Some(current) = bubble_up {
            // Update depth and rebalance
            self.do_rebalance(&current);
            // Decrement parent's child count for current
            let parent_weak = current.borrow().parent_node.clone();
            if let Some(ref p) = parent_weak.as_ref().and_then(|w| w.upgrade()) {
                let is_left;
                {
                    let pb = p.borrow();
                    is_left = pb.left_child_node.as_ref().map_or(false, |l| Rc::ptr_eq(l, &current));
                }
                if is_left {
                    p.borrow_mut().left_child_count -= 1;
                } else {
                    p.borrow_mut().right_child_count -= 1;
                }
            }
            bubble_up = parent_weak.and_then(|w| w.upgrade());
        }

        // Update root
        self.update_root();

        // Mark detached node as invalid
        detach_node.borrow_mut().weak_ref_node_valid = 0;
        detach_node.borrow_mut().weak_ref_count -= 1;
    }

    fn rebalance(&mut self, node: &Rc<RefCell<BOSNode>>) -> Option<Rc<RefCell<BOSNode>>> {
        self.do_rebalance(node);
        node.borrow().parent_node.as_ref().and_then(|w| w.upgrade())
    }

    fn do_rebalance(&mut self, node: &Rc<RefCell<BOSNode>>) {
        let left = node.borrow().left_child_node.clone();
        let right = node.borrow().right_child_node.clone();
        let ld = child_depth(&left);
        let rd = child_depth(&right);
        node.borrow_mut().depth = imax(ld, rd);
        let balance = (rd as i32) - (ld as i32);
        if balance > 1 {
            let right_balance;
            {
                let r = right.as_ref().unwrap().borrow();
                let rld = child_depth(&r.left_child_node);
                let rrd = child_depth(&r.right_child_node);
                right_balance = (rrd as i32) - (rld as i32);
            }
            if right_balance < 0 {
                let r_ref = Rc::clone(right.as_ref().unwrap());
                self.rotate_right(&r_ref);
            }
            self.rotate_left(node);
        } else if balance < -1 {
            let left_balance;
            {
                let l = left.as_ref().unwrap().borrow();
                let lld = child_depth(&l.left_child_node);
                let lrd = child_depth(&l.right_child_node);
                left_balance = (lrd as i32) - (lld as i32);
            }
            if left_balance > 0 {
                let l_ref = Rc::clone(left.as_ref().unwrap());
                self.rotate_left(&l_ref);
            }
            self.rotate_right(node);
        }
    }

    fn rotate_left(&mut self, p: &Rc<RefCell<BOSNode>>) -> Rc<RefCell<BOSNode>> {
        let r;
        let parent_weak;
        {
            let pb = p.borrow();
            r = Rc::clone(pb.right_child_node.as_ref().unwrap());
            parent_weak = pb.parent_node.clone();
        }
        if let Some(ref parent_rc) = parent_weak.as_ref().and_then(|w| w.upgrade()) {
            let is_left;
            {
                let prb = parent_rc.borrow();
                is_left = prb.left_child_node.as_ref().map_or(false, |l| Rc::ptr_eq(l, p));
            }
            if is_left {
                parent_rc.borrow_mut().left_child_node = Some(Rc::clone(&r));
            } else {
                parent_rc.borrow_mut().right_child_node = Some(Rc::clone(&r));
            }
        } else {
            self.root_node = Some(Rc::clone(&r));
        }
        r.borrow_mut().parent_node = parent_weak;
        let r_left = r.borrow().left_child_node.clone();
        let r_left_count = r.borrow().left_child_count;
        p.borrow_mut().right_child_node = r_left.clone();
        p.borrow_mut().right_child_count = r_left_count;
        if let Some(ref c) = r_left {
            c.borrow_mut().parent_node = Some(Rc::downgrade(p));
        }
        let pld = child_depth(&p.borrow().left_child_node);
        let prd = child_depth(&p.borrow().right_child_node);
        p.borrow_mut().depth = imax(pld, prd);
        p.borrow_mut().parent_node = Some(Rc::downgrade(&r));
        r.borrow_mut().left_child_node = Some(Rc::clone(p));
        let plc = p.borrow().left_child_count;
        let prc = p.borrow().right_child_count;
        r.borrow_mut().left_child_count = plc + prc + 1;
        let rld = child_depth(&r.borrow().left_child_node);
        let rrd = child_depth(&r.borrow().right_child_node);
        r.borrow_mut().depth = imax(rld, rrd);
        r
    }

    fn rotate_right(&mut self, p: &Rc<RefCell<BOSNode>>) -> Rc<RefCell<BOSNode>> {
        let l;
        let parent_weak;
        {
            let pb = p.borrow();
            l = Rc::clone(pb.left_child_node.as_ref().unwrap());
            parent_weak = pb.parent_node.clone();
        }
        if let Some(ref parent_rc) = parent_weak.as_ref().and_then(|w| w.upgrade()) {
            let is_left;
            {
                let prb = parent_rc.borrow();
                is_left = prb.left_child_node.as_ref().map_or(false, |l| Rc::ptr_eq(l, p));
            }
            if is_left {
                parent_rc.borrow_mut().left_child_node = Some(Rc::clone(&l));
            } else {
                parent_rc.borrow_mut().right_child_node = Some(Rc::clone(&l));
            }
        } else {
            self.root_node = Some(Rc::clone(&l));
        }
        l.borrow_mut().parent_node = parent_weak;
        let l_right = l.borrow().right_child_node.clone();
        let l_right_count = l.borrow().right_child_count;
        p.borrow_mut().left_child_node = l_right.clone();
        p.borrow_mut().left_child_count = l_right_count;
        if let Some(ref c) = l_right {
            c.borrow_mut().parent_node = Some(Rc::downgrade(p));
        }
        let pld = child_depth(&p.borrow().left_child_node);
        let prd = child_depth(&p.borrow().right_child_node);
        p.borrow_mut().depth = imax(pld, prd);
        p.borrow_mut().parent_node = Some(Rc::downgrade(&l));
        l.borrow_mut().right_child_node = Some(Rc::clone(p));
        let plc = p.borrow().left_child_count;
        let prc = p.borrow().right_child_count;
        l.borrow_mut().right_child_count = plc + prc + 1;
        let lld = child_depth(&l.borrow().left_child_node);
        let lrd = child_depth(&l.borrow().right_child_node);
        l.borrow_mut().depth = imax(lld, lrd);
        l
    }

    fn update_root(&mut self) {
        if let Some(ref root) = self.root_node {
            let mut current = Rc::clone(root);
            loop {
                let parent_weak = current.borrow().parent_node.clone();
                match parent_weak.and_then(|p| p.upgrade()) {
                    Some(parent) => current = parent,
                    None => break,
                }
            }
            self.root_node = Some(current);
        }
    }

    pub fn bostree_node_weak_unref(&mut self, node: &Rc<RefCell<BOSNode>>) -> Option<Rc<RefCell<BOSNode>>> {
        node.borrow_mut().weak_ref_count -= 1;
        if node.borrow().weak_ref_count == 0 {
            if let Some(f) = self.free_function { f(node); }
            None
        } else if node.borrow().weak_ref_node_valid != 0 {
            Some(Rc::clone(node))
        } else { None }
    }

    pub fn bostree_lookup(&self, key: &str) -> Option<Rc<RefCell<BOSNode>>> {
        let mut cur = self.root_node.as_ref().map(Rc::clone);
        while let Some(node) = cur {
            let cmp;
            let next;
            {
                let nb = node.borrow();
                cmp = (self.cmp_function)(key, &nb.key);
                next = if cmp == 0 { None } else if cmp < 0 { nb.left_child_node.clone() } else { nb.right_child_node.clone() };
            }
            if cmp == 0 { return Some(node); }
            cur = next;
        }
        None
    }

    pub fn bostree_select(&self, index: u32) -> Option<Rc<RefCell<BOSNode>>> {
        let mut cur = self.root_node.as_ref().map(Rc::clone);
        let mut idx = index;
        while let Some(node) = cur {
            let found;
            let next;
            {
                let nb = node.borrow();
                if nb.left_child_count <= idx {
                    let rem = idx - nb.left_child_count;
                    if rem == 0 { (found, next) = (true, None); }
                    else { idx = rem - 1; (found, next) = (false, nb.right_child_node.clone()); }
                } else { (found, next) = (false, nb.left_child_node.clone()); }
            }
            if found { return Some(node); }
            cur = next;
        }
        None
    }

    #[cfg(debug_assertions)]
    pub fn bostree_print(&self) { if let Some(ref root) = self.root_node { println!("digraph {{\n  ordering = out;"); Self::print_helper(root); println!("}}"); } }
    #[cfg(debug_assertions)]
    fn print_helper(node: &Rc<RefCell<BOSNode>>) {
        let n = node.borrow();
        println!("  {} [label=\"\\N ({},{},{})\"];", n.key, n.left_child_count, n.right_child_count, n.depth);
        if let Some(ref p) = n.parent_node.as_ref().and_then(|w| w.upgrade()) { println!("  {} -> {} [color=green];", n.key, p.borrow().key); }
        if let Some(ref left) = n.left_child_node { println!("  {} -> {}", n.key, left.borrow().key); Self::print_helper(left); }
        if let Some(ref right) = n.right_child_node { println!("  {} -> {}", n.key, right.borrow().key); Self::print_helper(right); }
    }
}

pub fn bostree_node_weak_ref(node: &Rc<RefCell<BOSNode>>) -> Rc<RefCell<BOSNode>> { node.borrow_mut().weak_ref_count += 1; Rc::clone(node) }

pub fn bostree_next_node(node: &Rc<RefCell<BOSNode>>) -> Option<Rc<RefCell<BOSNode>>> {
    if let Some(ref right) = node.borrow().right_child_node {
        let mut cur = Rc::clone(right);
        while cur.borrow().left_child_node.is_some() { let next = Rc::clone(cur.borrow().left_child_node.as_ref().unwrap()); cur = next; }
        Some(cur)
    } else {
        let mut cur = Rc::clone(node);
        loop { let p = cur.borrow().parent_node.as_ref().and_then(|w| w.upgrade()); match p { Some(parent) => { if parent.borrow().right_child_node.as_ref().map_or(false, |r| Rc::ptr_eq(r, &cur)) { cur = parent; } else { return Some(parent); } } None => return None, } }
    }
}

pub fn bostree_previous_node(node: &Rc<RefCell<BOSNode>>) -> Option<Rc<RefCell<BOSNode>>> {
    if let Some(ref left) = node.borrow().left_child_node {
        let mut cur = Rc::clone(left);
        while cur.borrow().right_child_node.is_some() { let next = Rc::clone(cur.borrow().right_child_node.as_ref().unwrap()); cur = next; }
        Some(cur)
    } else {
        let mut cur = Rc::clone(node);
        loop { let p = cur.borrow().parent_node.as_ref().and_then(|w| w.upgrade()); match p { Some(parent) => { if parent.borrow().left_child_node.as_ref().map_or(false, |l| Rc::ptr_eq(l, &cur)) { cur = parent; } else { return Some(parent); } } None => return None, } }
    }
}

pub fn bostree_rank(node: &Rc<RefCell<BOSNode>>) -> u32 {
    let mut counter = node.borrow().left_child_count;
    let mut cur = Rc::clone(node);
    loop { let p = cur.borrow().parent_node.as_ref().and_then(|w| w.upgrade()); match p { Some(parent) => { if parent.borrow().right_child_node.as_ref().map_or(false, |r| Rc::ptr_eq(r, &cur)) { counter += 1 + parent.borrow().left_child_count; } cur = parent; } None => return counter, } }
}
